const items = $input.all().map(i => i.json);

// Organiza por período e campanha
const dados = {};

for (const item of items) {
	if (!dados[item.periodo]) dados[item.periodo] = {};
	dados[item.periodo][item.campanha] = item;
}

function variacao(atual, anterior) {
	atual = Number(atual);
	anterior = Number(anterior);

	if (!isFinite(atual) || !isFinite(anterior) || anterior === 0) {
		return null;
	}

	return ((atual - anterior) / anterior) * 100;
}

function direcao(atual, anterior, menorMelhor = false, tolerancia = 0) {
	atual = Number(atual);
	anterior = Number(anterior);

	if (!isFinite(atual) || !isFinite(anterior)) {
		return "➖";
	}

	const diferenca = atual - anterior;

	if (Math.abs(diferenca) <= tolerancia) {
		return "➖";
	}

	if (menorMelhor) {
		return diferenca < 0 ? "⬆️" : "⬇️";
	}

  	return diferenca > 0 ? "⬆️" : "⬇️";
}

function compararCampanha(nome) {

	const atual = dados.atual?.[nome];
	const anterior = dados.anterior?.[nome];

	if (!atual || !anterior) {
		return null;
	}

	const resultado = {
		atual,
		anterior,
		comparativo: {

			investimento: {
				variacao: variacao(atual.investimento, anterior.investimento),
				icone: direcao(
					variacao(atual.investimento, anterior.investimento),
					0,
					false,
					10
				)
			},

			impressoes: {
				variacao: variacao(atual.impressoes, anterior.impressoes),
				icone: direcao(atual.impressoes, anterior.impressoes)
			},

			alcance: {
				variacao: variacao(atual.alcance, anterior.alcance),
				icone: direcao(atual.alcance, anterior.alcance)
			},

			cliques: {
				variacao: variacao(atual.cliques, anterior.cliques),
				icone: direcao(atual.cliques, anterior.cliques)
			},

			ctr: {
				variacao_pp:
					Number(atual.ctr) -
					Number(anterior.ctr),

				icone: direcao(
					atual.ctr,
					anterior.ctr,
					false,
					0.2
				)
			},

			cpc: {
				variacao: variacao(atual.cpc, anterior.cpc),

				icone: direcao(
					variacao(atual.cpc, anterior.cpc),
					0,
					true,
					5
				)
			}

		}
	};

	// ===========================
	// CAMPANHAS DE DISTRIBUIÇÃO
	// ===========================

	if (nome === "DISTRIBUICAO") {

		resultado.comparativo.post_engagement = {
			variacao: variacao(
				atual.post_engagement,
				anterior.post_engagement
			),

			icone: direcao(
				atual.post_engagement,
				anterior.post_engagement
			)
		};

		return resultado;
	}

	// ===========================
	// CAMPANHAS DE VENDA
	// (VASO, PED, ORQ, CAPTURA...)
	// ===========================

	resultado.comparativo.visitas_pagina = {

		variacao: variacao(
			atual.visitas_pagina,
			anterior.visitas_pagina
		),

		icone: direcao(
			atual.visitas_pagina,
			anterior.visitas_pagina
		)

	};

	resultado.comparativo.connect_rate = {

		variacao_pp:
			Number(atual.connect_rate) -
			Number(anterior.connect_rate),

		icone: direcao(
			atual.connect_rate,
			anterior.connect_rate,
			false,
			5
		)

	};

	resultado.comparativo.conversao_pagina = {

		variacao_pp:
			Number(atual.conversao_pagina) -
			Number(anterior.conversao_pagina),

		icone: direcao(
			atual.conversao_pagina,
			anterior.conversao_pagina,
			false,
			5
		)

	};

	resultado.comparativo.conversao_checkout = {

		variacao_pp:
			Number(atual.conversao_checkout) -
			Number(anterior.conversao_checkout),

		icone: direcao(
			atual.conversao_checkout,
			anterior.conversao_checkout,
			false,
			5
		)

	};

	resultado.comparativo.vendas_trafego = {

		variacao: variacao(
			atual.vendas_trafego,
			anterior.vendas_trafego
		),

		icone: direcao(
			atual.vendas_trafego,
			anterior.vendas_trafego
		)

	};

	resultado.comparativo.custo_por_compra = {

		variacao: variacao(
			atual.custo_por_compra,
			anterior.custo_por_compra
		),

		icone: direcao(
			variacao(
				atual.custo_por_compra,
				anterior.custo_por_compra
			),
			0,
			true,
			10
		)

	};

	resultado.comparativo.roas = {

		variacao: variacao(
			atual.roas,
			anterior.roas
		),

		icone: direcao(
			variacao(
				atual.roas,
				anterior.roas
			),
			0,
			false,
			10
		)

	};

	return resultado;
}

// Descobre automaticamente todas as campanhas
const campanhas = new Set([
	...Object.keys(dados.atual || {}),
	...Object.keys(dados.anterior || {})
]);

const retorno = {};

for (const campanha of campanhas) {

	const resultado = compararCampanha(campanha);

	if (resultado) {
		retorno[campanha] = resultado;
	}

}

return [
	{
		json: retorno
	}
];

